import{_ as e,o as a,c as n,a2 as r}from"./chunks/framework.pnUkSPAE.js";const o="/diagrams/agent-arch.svg",i="/diagrams/react-loop.svg",A=JSON.parse('{"title":"5.1-5.3 Agent 核心概念与设计模式","description":"","frontmatter":{"title":"5.1-5.3 Agent 核心概念与设计模式"},"headers":[],"relativePath":"guide/stage5-agent-arch.md","filePath":"guide/stage5-agent-arch.md"}'),g={name:"guide/stage5-agent-arch.md"};function s(l,t,h,d,c,p){return a(),n("div",null,[...t[0]||(t[0]=[r('<blockquote><p>[日期] 预计学习时间：40-50 小时</p></blockquote><h2 id="_5-1-ai-agent-核心概念" tabindex="-1">5.1 AI Agent 核心概念 <a class="header-anchor" href="#_5-1-ai-agent-核心概念" aria-label="Permalink to &quot;5.1 AI Agent 核心概念&quot;">​</a></h2><p>AI Agent 是能<strong>自主感知环境、做出决策、使用工具、完成目标</strong>的 AI 系统。</p><p><strong>Agent 的核心循环：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>感知 → 推理 → 行动 → 观察 → 感知 → ...</span></span></code></pre></div><h2 id="_5-2-agent-核心组件" tabindex="-1">5.2 Agent 核心组件 <a class="header-anchor" href="#_5-2-agent-核心组件" aria-label="Permalink to &quot;5.2 Agent 核心组件&quot;">​</a></h2><img src="'+o+'" alt="Agent核心架构" style="max-width:100%;height:auto;"><table tabindex="0"><thead><tr><th>组件</th><th>说明</th><th>大厂关注点</th></tr></thead><tbody><tr><td>LLM（大脑）</td><td>推理和决策</td><td>模型选型、成本控制</td></tr><tr><td>Memory（记忆）</td><td>短期/长期记忆</td><td>记忆管理架构、上下文窗口优化</td></tr><tr><td>Tools（工具）</td><td>与外部系统交互</td><td>MCP 标准化、权限控制</td></tr><tr><td>Planning（规划）</td><td>分解复杂任务</td><td>CoT、ReAct、多步推理</td></tr></tbody></table><h2 id="_5-3-经典设计模式" tabindex="-1">5.3 经典设计模式 <a class="header-anchor" href="#_5-3-经典设计模式" aria-label="Permalink to &quot;5.3 经典设计模式&quot;">​</a></h2><img src="'+i+'" alt="ReAct循环" style="max-width:100%;height:auto;"><p><strong>模式一：ReAct（Reasoning + Acting）</strong> — 最经典，交替推理和行动</p><p><strong>模式二：Plan-and-Execute</strong> — 先规划后执行，适合复杂任务</p><p><strong>模式三：多 Agent 协作（Multi-Agent）</strong></p><ul><li><strong>主从模式（Orchestrator-Worker）：</strong> 字节跳动 Coze 的核心模式</li><li><strong>辩论模式（Debate）：</strong> 多 Agent 讨论，达成共识</li><li><strong>流水线模式（Pipeline）：</strong> 串行处理</li></ul><p><strong>模式四：Reflection（自我反思）</strong> — Agent 检查输出，发现问题后修正</p><p><strong>大厂面试常问：</strong></p><ul><li>&quot;ReAct 和 Plan-and-Execute 的区别？&quot; → ReAct 是逐步推理执行，Plan-and-Execute 是先完整规划再执行</li><li>&quot;如何防止 Agent 死循环？&quot; → 设置最大步数、超时机制、重复检测</li><li>&quot;多 Agent 协作的通信机制？&quot; → 共享状态、消息队列、MCP/A2A 协议</li></ul><h3 id="学习资料清单" tabindex="-1">学习资料清单 <a class="header-anchor" href="#学习资料清单" aria-label="Permalink to &quot;学习资料清单&quot;">​</a></h3><p><strong>论文：</strong></p><ul><li>&quot;ReAct: Synergizing Reasoning and Acting in Language Models&quot;：<a href="https://arxiv.org/abs/2210.03629" target="_blank" rel="noreferrer">https://arxiv.org/abs/2210.03629</a></li><li>&quot;LLM Powered Autonomous Agents&quot; (Lilian Weng)：<a href="https://lilianweng.github.io/posts/2023-06-23-agent/" target="_blank" rel="noreferrer">https://lilianweng.github.io/posts/2023-06-23-agent/</a></li><li>&quot;A Survey on Large Language Model based Autonomous Agents&quot;：<a href="https://arxiv.org/abs/2308.11432" target="_blank" rel="noreferrer">https://arxiv.org/abs/2308.11432</a></li><li>&quot;Reflexion: Language Agents with Verbal Reinforcement Learning&quot;：<a href="https://arxiv.org/abs/2303.11366" target="_blank" rel="noreferrer">https://arxiv.org/abs/2303.11366</a></li></ul><p><strong>GitHub：</strong></p><ul><li><code>langchain-ai/langgraph</code> — LangGraph 官方仓库：<a href="https://github.com/langchain-ai/langgraph" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langgraph</a></li><li><code>datawhalechina/hello-agents</code> — Datawhale Agent 教程（中文）：<a href="https://github.com/datawhalechina/hello-agents" target="_blank" rel="noreferrer">https://github.com/datawhalechina/hello-agents</a></li></ul><p><strong>课程：</strong></p><ul><li>Andrew Ng《AI Agentic Design Patterns》（DeepLearning.AI，免费）：<a href="https://www.deeplearning.ai/short-courses/ai-agentic-design-patterns/" target="_blank" rel="noreferrer">https://www.deeplearning.ai/short-courses/ai-agentic-design-patterns/</a></li></ul>',24)])])}const b=e(g,[["render",s]]);export{A as __pageData,b as default};
